    #[default]
    Blocking,
    Subtle,
    Skeleton,
}

impl OverlayMode {
    pub fn as_str(&self) -> &'static str {
        match self {
            OverlayMode::Blocking => "blocking",
            OverlayMode::Subtle   => "subtle",
            OverlayMode::Skeleton => "skeleton",
        }
    }
}

#[component]
